import sailpoint.object.Identity;
import java.util.HashMap;
import sailpoint.transformer.IdentityTransformer;

HashMap model = new HashMap();
IdentityTransformer transformer = new IdentityTransformer(context);
model.put(IdentityTransformer.ATTR_TRANSFORMER_CLASS, transformer.getClass().getName());
model.put(IdentityTransformer.ATTR_TRANSFORMER_OPTIONS, "");
return model;

ValidationScript.Source:
import sailpoint.object.Identity;
import sailpoint.api.IdentityService;
import sailpoint.object.Link;
import sailpoint.object.Application;
import sailpoint.object.Filter;

Filter f = Filter.or(Filter.eq("id",value),Filter.eq("name",value));

Identity ideObject = context.getUniqueObject(Identity.class,f);

Application appObject = context.getObjectByName(Application.class,formModel.get("aApplicationName"));

IdentityService service = new IdentityService(context);

List links = service.getLinks(ideObject,appObject);

if(links != null @and links.size() > 0){

for(Link link:links){

if(link.getDisplayName().equals(ideObject.getName()+"adm")){

return "This identity already have Admin account in this "+formModel.get("aApplicationName");
}
}
return null;
}
else{
return "this user do not have account in this "+formModel.get("aApplicationName");
}

